// Score each candidate 0-100 from simple heuristics
return $input.all().map(item => {
  const j = item.json;
  let score = 50;
  if (j.email) score += 20;
  if (j.role) score += 15;
  if ((j.source || '') === 'referral') score += 15;
  return { json: { ...j, score: Math.min(100, score) } };
});

// Round-robin owner assignment
const owners = ['ava@company.com', 'liam@company.com', 'mia@company.com'];
return $input.all().map((item, i) => ({
  json: { ...item.json, owner: owners[i % owners.length] },
}));

// Build a stable idempotency key per candidate (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.candidateId, j.email].join('|')) } };
});
